	public override void Action(RuleContext _localctx, int ruleIndex, int actionIndex) {
		switch (ruleIndex) {
		case 352 : LPAREN_action(_localctx, actionIndex); break;
		case 366 : PIC_STRING_action(_localctx, actionIndex); break;
		}
	}
	private void LPAREN_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 0:  if (_lastNonWsTokenType == IDENTIFIER
		                          || _lastNonWsTokenType == DISPLAY
		                          || _lastNonWsTokenType == LENGTH
		                          || _lastNonWsTokenType == MERGE
		                          || _lastNonWsTokenType == NATIONAL
		                          || _lastNonWsTokenType == NORMAL
		                          || _lastNonWsTokenType == RANDOM
		                          || _lastNonWsTokenType == SIGN
		                          || _lastNonWsTokenType == SORT
		                          || _lastNonWsTokenType == SUM)
		                         PushMode(SUBSCRIPT);  break;
		}
	}
	private void PIC_STRING_action(RuleContext _localctx, int actionIndex) {
		switch (actionIndex) {
		case 1: 
		        // Handle PIC "999999999999.." — greedy match consumed sentence-ending period.
		        // If the PIC string ends with '.' and the char that caused the match was also '.',
		        // trim the trailing period and back up so it becomes a DOT token.
		        var t = Text;
		        if (t.Length > 1 && t[t.Length - 1] == '.')
		        {
		            Text = t.Substring(0, t.Length - 1);
		            InputStream.Seek(InputStream.Index - 1);
		        }
		     break;
		}
	}

